    professionSlugs: ['disenador-ux', 'disenador-ui', 'disenador-web', 'desarrollador-frontend', 'desarrollador-web', 'disenador-grafico'],
    atsKeywords: ['diseño UX', 'experiencia de usuario', 'UX', 'investigación de usuarios', 'pruebas de usabilidad', 'wireframing', 'prototipado', 'arquitectura de información', 'diseño centrado en el usuario', 'design thinking', 'accesibilidad', 'diseño de interacción'],
